/**
 * Returns audit rows for a bounded time range.
 *
 * @fromDate Inclusive start timestamp.
 * @toDate Inclusive end timestamp.
 * @return query
 */
public query function getAuditRange(required date fromDate, required date toDate) {
  return queryExecute(
    'SELECT id, action, createdAt FROM audit_log WHERE createdAt >= :fromDate AND createdAt <= :toDate',
    {
      fromDate: { value: arguments.fromDate, cfsqltype: 'cf_sql_timestamp' },
      toDate: { value: arguments.toDate, cfsqltype: 'cf_sql_timestamp' }
    },
    { datasource: variables.datasource }
  );
}

/**
 * Deletes a pending invitation by token.
 *
 * @inviteToken Invitation token UUID.
 * @return numeric
 */
public numeric function deleteInvite(required string inviteToken) {
  var result = queryExecute(
    'DELETE FROM user_invites WHERE inviteToken = :inviteToken',
    { inviteToken: { value: arguments.inviteToken, cfsqltype: 'cf_sql_varchar' } },
    { datasource: variables.datasource, result: 'deleteResult' }
  );
  return result.recordCount;
}

/**
 * Builds a view-safe profile summary payload.
 *
 * @displayName User-provided display name.
 * @profileSlug URL slug segment.
 * @return struct
 */
public struct function buildSafeProfileOutput(required string displayName, required string profileSlug) {
  return {
    safeDisplayName: encodeForHTML(arguments.displayName),
    safeProfileUrl: '/profile/' & encodeForURL(arguments.profileSlug)
  };
}

/**
 * Validates CSRF token before processing update.
 *
 * @rc Request collection containing csrfToken.
 * @return void
 * @throws application When CSRF token validation fails.
 */
public void function validateCsrf(required struct rc) {
  if (!structKeyExists(arguments.rc, 'csrfToken') || arguments.rc.csrfToken != session.csrfToken) {
    throw(type = 'application', message = 'Invalid CSRF token.');
  }
}

/**
 * Validates uploaded file metadata before storage.
 *
 * @uploadInfo Struct from upload handling pipeline.
 * @return void
 * @throws application When validation fails.
 */
public void function validateUpload(required struct uploadInfo) {
  var allowedMimeTypes = ['image/jpeg', 'image/png', 'application/pdf'];
  if (!allowedMimeTypes.contains(arguments.uploadInfo.contentType)) {
    throw(type = 'application', message = 'Unsupported file type.');
  }
  if (arguments.uploadInfo.fileSize > 5 * 1024 * 1024) {
    throw(type = 'application', message = 'File exceeds 5MB limit.');
  }
}

/**
 * Returns secure session settings for Application.cfc.
 *
 * @return struct
 */
public struct function getSecureSessionConfig() {
  return {
    sessionManagement: true,
    setClientCookies: true,
    sessionCookie: {
      httpOnly: true,
      secure: true,
      sameSite: 'Lax'
    }
  };
}

/**
 * Stores a short-lived security token in a dedicated named cache region.
 * Requires CF2023+ for named cache region support.
 *
 * @tokenKey  string  Cache key for this token (e.g. 'csrf_#session.userId#').
 * @token     string  Token value to store.
 */
public void function storeSecurityToken(
    required string tokenKey,
    required string token
) {
    // CF2023+: store in named region with 2-hour expiry
    cachePut(
        arguments.tokenKey,
        arguments.token,
        createTimeSpan(0, 2, 0, 0),
        "",
        { region: "security-tokens" }
    );
}

/**
 * Validates and consumes a token from the named cache region.
 * Invalidates on first use to prevent replay.
 */
public boolean function validateAndConsumeToken(
    required string tokenKey,
    required string expectedToken
) {
    var stored = cacheGet(arguments.tokenKey, { region: "security-tokens" });
    if (isNull(stored) || stored != arguments.expectedToken) {
        return false;
    }
    cacheRemove(arguments.tokenKey, false, { region: "security-tokens" });
    return true;
}

