    lock scope='application' type='exclusive' timeout='5' {
        application.securityTokens[arguments.tokenKey] = { token: arguments.token, expires: expiry };
    }
}
public boolean function validateAndConsumeToken(required string tokenKey, required string expectedToken) {
    var entry = {};
    lock scope='application' type='exclusive' timeout='5' {
        if (!structKeyExists(application.securityTokens, arguments.tokenKey)) { return false; }
        entry = application.securityTokens[arguments.tokenKey];
        structDelete(application.securityTokens, arguments.tokenKey);
    }
    return (entry.token == arguments.expectedToken && entry.expires >= now());
